var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"전조 프로토콜 3시간 전","JPN":"前兆プロトコル3時間前","ENG":"3 hours before the Omen Protocol","TWN":"前兆協議3小時前"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"관리국 직할 도시 <color=#ffd34c>샤레이드</color> 상업 지구\\n플라티나 익스프레스 사옥, 옥상","JPN":"管理局直轄都市<color=#ffd34c>シャレード</color>商業地区\\nプラチナエクスプレス社、屋上","ENG":"Administration Direct Control City, <color=#ffd34c>Charade</color> Commercial District\\nPlatina Express Headquarters, Rooftop","TWN":"管理局直轄城市<color=#ffd34c>查雷德</color>商業區\\n白金運通辦公樓，屋頂"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"후우…….","JPN":"ふう……","ENG":"Phew...","TWN":"呼……"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L8_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"어쩐지 오늘은 평소보다 배달 물량이 많은데?","JPN":"なんかいつもより配達量多くない？","ENG":"Feels like there are more deliveries than usual today, doesn't it?","TWN":"我總覺得今天的配送量比平常還多耶？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L9_1","type":"dialog","speaker":"PUPPET_OZ_NULL_NULL","text":{"KOREA":"그야 라라 선배가 휴가를 썼거든. 그래서 신입들도 할당량도 늘어난 거지.","JPN":"ララ先輩が有休取ったからね。だから新入りのノルマも増えたんだ。","ENG":"That is because Lara took some time off. The new hires got extra quotas too.","TWN":"因為拉拉前輩請假了啊，所以新人的配額也跟著增加了。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"으음? 라라 선배가 휴가라고? 그게 정말이야?","JPN":"ん？　ララ先輩が有休？　それマジ？","ENG":"Huh? Lara's on vacation? Really?","TWN":"咦？拉拉前輩請假？真的假的？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"PUPPET_OZ_NULL_NULL","text":{"KOREA":"글쎄? 무슨 세계의 운명이 달린 딜리버리 서비스라고 하던데……?","JPN":"さあ？　世界の運命がかかったデリバリーサービスとかなんとか言ってたけど……？","ENG":"Not sure. She said something about a delivery tied to the fate of the world or something like that...","TWN":"對啊？好像說是什麼「攸關世界命運的外送任務」之類的……？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"PUPPET_OZ_NULL_NULL","text":{"KOREA":"선배 말이 너무 빨라서 잘 못 알아 들었어.","JPN":"先輩早口すぎて、よく聞き取れなかった。","ENG":"She talks so fast that I could not really catch it.","TWN":"前輩講太快了，我也沒聽清楚。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"세계의 운명이라고…? 하하, 하여간 그 선배도 참 괴짜라니까……?","JPN":"世界の運命……？　はは、まあ先輩って変わり者だしな……","ENG":"The fate of the world...? Haha, she really is a weirdo...","TWN":"世界的命運……？哈哈，前輩果然也是個怪人……？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"PUPPET_OZ_NULL_NULL","text":{"KOREA":"하지만 배달 실력은 확실하잖아?","JPN":"でも配達の腕は確かでしょ？","ENG":"Still, you cannot deny her delivery skills.","TWN":"不過她的配送實力真的很厲害啊？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L18_1","type":"dialog","speaker":"PUPPET_OZ_NULL_NULL","text":{"KOREA":"입사 이래, 플래티넘 랭크의 영광을 단 한 번도 놓친 적 없는 배달 업계의 전설…….","JPN":"入社以来、プラチナランクの栄光を一度も逃したことのない、配達業界の伝説……","ENG":"Since joining, she has never once lost her Platinum Rank. A legend in the delivery business.","TWN":"入職後，從沒失去過白金獎的送貨界傳奇……"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_07","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"PUPPET_OZ_NULL_NULL","text":{"KOREA":"소문에 따르면, 이 도시 물류의 30% 이상은 선배 혼자 담당하고 있다고 하더라.","JPN":"この都市の物流の3割以上を、先輩1人が担当しているって噂だよ。","ENG":"I heard she handles over thirty percent of this city's logistics all by herself.","TWN":"據說她一個人扛下了這座城市30%以上的物流。"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_07","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"나도 들었어. 신속, 정확, 안전 그리고 고객님의 미소였나?","JPN":"あ、知ってる。迅速、正確、安全、あとお客様の笑顔だっけ？","ENG":"Yeah, I heard that too. Speed, accuracy, safety, and the customer's smile, right?","TWN":"我也聽說過。迅速、精準、安全，還有顧客的笑容。"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_07","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"PUPPET_OZ_NULL_NULL","text":{"KOREA":"이 회사가 업계 1등 배달 업체가 된 건, 전부 그 선배 덕분이라고 할 수 있지.","JPN":"この会社が配達業界NO.1になれたのは、全部先輩のおかげと言えるね。","ENG":"You could say this company became the top delivery service entirely thanks to her.","TWN":"公司能成為業界第一，可以說全都是前輩的功勞吧。"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_07","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"PUPPET_OZ_NULL_NULL","text":{"KOREA":"물론, 회사 높으신 분들이 그 공로를 알아주는지는 잘 모르겠지만.","JPN":"まあ、会社の偉い人たちがそれをわかってくれてるかは知らないけど。","ENG":"Though I am not sure the higher-ups really recognize her contributions.","TWN":"當然，但就不知道高層到底有沒有認真看待這份功勞了。"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_07","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"아하하… 그건 그렇지…….","JPN":"あはは……それはそうだね……","ENG":"Haha... Yeah, that sounds about right...","TWN":"啊哈哈……這倒也是……"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"선배한테 들었는데, 플래티넘 랭크를 받는다고 수당을 더 쳐주는 것 같지는 않더라.","JPN":"先輩の話だと、別にプラチナランクだからって手当が増えるとかでもなさそうだし。","ENG":"I heard from her that Platinum Rank does not even come with extra pay.","TWN":"我聽前輩說過，就算拿到白金獎，好像也不會多給補助。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"PUPPET_OZ_NULL_NULL","text":{"KOREA":"켁, 뭐야? 완전 블랙 기업이었잖아?","JPN":"げっ。何それ、超ブラック企業じゃない。","ENG":"What? Seriously? That is a full-on black company.","TWN":"咦？搞什麼，這根本是黑心企業吧？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L30_1","type":"dialog","speaker":"PUPPET_OZ_NULL_NULL","text":{"KOREA":"레드 리코리스… 편입할 때까지 괜찮은 일자리를 알선해준다더니, 우리를 속였어…….","JPN":"レッドリコリス……編入するまでの間いい仕事を紹介するって言って、ワタシたちを騙したな……","ENG":"Red Lycoris said they would help us find decent jobs until we were transferred, and they totally lied.","TWN":"紅髮莉克麗絲……不是說會在編入前幫我們安排好工作嗎？我們被騙了……"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"뭐, 그래도 위저드 때보다는 떳떳하게 돈을 벌 수 있잖아?","JPN":"まあでも、ウィザードの時に比べれば、もっと胸を張れる稼ぎ方なのは確かよね。","ENG":"Well, at least it is more honest money than when we were at Wizard.","TWN":"不過嘛，至少比當魔法師賺錢時光明正大多了吧？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"회사 평판이 그다지 좋지는 않지만, 딱히 불법적인 일도 아니고.","JPN":"会社の評判はイマイチだけど、別に違法行為やってるわけじゃないし。","ENG":"The company's reputation is not great, but it's not illegal either.","TWN":"雖然公司名聲不怎麼樣，但也沒做什麼違法的事。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"당장은 관리국 세이프 하우스에서 신세지고 있지만, 언젠가 독립도 해야겠지.","JPN":"今は管理局のセーフハウスに世話になってるけど、いつかは独り立ちしないと。","ENG":"For now, we are staying at the Administration safe house, but someday we'll need to be independent.","TWN":"現在暫時寄住在管理局安全據點，不過總有一天也得獨立。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"그리고 무엇보다도… 나, 이 일이 제법 마음에 들거든.","JPN":"あと何より……私、この仕事が結構気に入ってるんだ。","ENG":"And more than anything... I actually like this job.","TWN":"而且最重要的是……我其實滿喜歡這份工作的。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"PUPPET_OZ_NULL_NULL","text":{"KOREA":"도로시……?","JPN":"ドロシー……？","ENG":"Dorothy...?","TWN":"桃樂絲……？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"이 레드 슈즈로 밤 공기를 가르면서, 배달하다 보면 꼭 그때가 생각나서 말이야.","JPN":"このレッドシューズで、夜の空気を突き抜けるように配達してると、以前の自分が思い浮かぶんだ。","ENG":"Cutting through the night air in these Red Shoes while making deliveries always makes me think of back then.","TWN":"每次穿著這雙紅鞋劃破夜晚的空氣奔馳、配送時，總會想起那段時光。"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_07","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"오로지 달리는 것 하나만을 떠올리던 시절. 그것만이 내 전부였던 시절…….","JPN":"走ることだけに没頭していた……それがすべてだった頃の自分が……","ENG":"Back when all I thought about was running. When that was my entire world...","TWN":"只想著奔跑，奔跑便是一切的時期……"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_07","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"물론, 이제 와서 더는 그 시절로 돌아갈 수는 없겠지만.","JPN":"あの頃に戻ることはできないけど。","ENG":"Of course, I can't go back to those days anymore.","TWN":"當然，現在已經不可能再回到那時候了。"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_07","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"지금은 이 속도가, 이 다리가…….","JPN":"今はこの速度が、この脚が……","ENG":"But now, this speed, these legs...","TWN":"但現在的速度，這雙腿……"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"어떤 형태로든, 누군가에게 도움이 될 수 있다는 사실 그 자체가 마음에 들어.","JPN":"どんな形であれ、誰かの役に立てる自分でいさせてくれる。","ENG":"The fact that they can help someone, in any way at all, that is what I like.","TWN":"不論什麼形式，光是能幫上別人的忙這件事本身就讓我很開心。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"이 일 덕분에 나보다도 더 빠른 사람도 만날 수 있게 됐고.","JPN":"この仕事のおかげで、私より速い人にも出会えたしね。","ENG":"Thanks to this job, I even got to meet people faster than me.","TWN":"也因為這份工作，才能遇見比我更快的人。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"그리고 언젠가는 꼭 선배를 이겨보고 싶어.","JPN":"いつか必ず、先輩には勝ってみせたい。","ENG":"And someday, I really want to beat her.","TWN":"而且總有一天，我一定要贏過前輩。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"PUPPET_OZ_NULL_NULL","text":{"KOREA":"라라 선배는 공간 도약 카운터야.","JPN":"ララ先輩は空間跳躍カウンターだよ。","ENG":"Lara is a Space-jumping Counter.","TWN":"拉拉前輩可是空間跳躍制裁者。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"PUPPET_OZ_NULL_NULL","text":{"KOREA":"네가 아무리 빨라져도 물리법칙을 거스르지 않는 이상, 선배를 이길 수는 없을걸?","JPN":"ドロシーがどんなに速くなっても、物理法則があるかぎり先輩には勝てないよ？","ENG":"No matter how fast you get, unless you break the laws of physics, you can't beat her.","TWN":"不管你再怎麼快，除非你能違反物理法則，不然也贏不了她吧？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"그런가? 내 생각은 좀 다른데?","JPN":"そう？　私はそう思わないけど。","ENG":"Is that so? I think differently.","TWN":"是嗎？我倒不這麼認為。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"속도로는 못 이겨도, 한 번쯤 선배한테서 플래티넘 랭크를 빼앗을 수 있지 않을까?","JPN":"速度じゃダメでも、プラチナランクを奪うだけなら、何とかできるんじゃない？","ENG":"Even if I can't beat her in speed, maybe I can steal the Platinum Rank from her at least once.","TWN":"就算速度比不上，難道不能從她手中搶下白金獎一次嗎？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"물론, 내 다리와 네 머리가 힘을 합한다면 말이야.","JPN":"私の脚とコトリの頭があればね。","ENG":"Of course, that is if my legs and your brain work together.","TWN":"當然，前提是我的腿和你的腦袋能聯手合作。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"PUPPET_OZ_NULL_NULL","text":{"KOREA":"플래티넘 랭크? 그렇지만 그건 아무런 의미가 없다면서?","JPN":"プラチナランク？　でもあれは意味ないんじゃなかった？","ENG":"Platinum Rank? But you said that did not really matter.","TWN":"白金獎？你不是說那根本沒什麼意義嗎？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L6_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"의미가 없기는 왜 없어?","JPN":"意味なくはないだろ。","ENG":"Why wouldn't it matter?","TWN":"怎麼會沒意義？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"이 다리로 있는 힘껏 달려서, 누군가가 미소 지을 수 있다면 그걸로 충분하잖아?","JPN":"この脚で精いっぱい走り抜けて、誰かを笑顔にできるならそれで十分さ。","ENG":"If running with everything I have makes someone smile, that's more than enough.","TWN":"用這雙腿拼盡全力奔跑，光是能讓某個人露出笑容這點，不就夠了嗎？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"PUPPET_OZ_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"PUPPET_OZ_NULL_NULL","text":{"KOREA":"하아, 그럼 어쩔 수 없네. 고지능 인간의 힘을 보여주지.","JPN":"はあ、じゃあ仕方ないね。高知能人間の力を見せてあげるよ。","ENG":"All right, I guess I have no choice. I will show you the power of a high-intelligence human.","TWN":"唉，那也沒辦法了。就讓你見識一下高智商人類的力量吧。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L13_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"그래, 좋아. 앞으로도 잘 부탁한다고, 파트너.","JPN":"うん。これからもよろしく、パートナー。","ENG":"Good. Looking forward to working with you, partner.","TWN":"好，今後也請多多指教了，夥伴。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L16_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"그나저나 리온은 잘 지내고 있으려나?","JPN":"それにしても、リオンは元気かな？","ENG":"By the way, do you think Liona's doing well?","TWN":"話說回來，萊恩最近過得還好嗎？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L17_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"카운터 아카데미에 편입했다고는 들었는데, 벌써 몇 달째 소식이 없네.","JPN":"カウンターアカデミーに編入したって話は聞いたけど、ここ数ヶ月特に連絡とかなかったし。","ENG":"I heard she transferred to the Counter Academy, but it's been months since we last heard from her.","TWN":"聽說他編入制裁者學院，但已經好幾個月沒消息了。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"PUPPET_OZ_NULL_NULL","text":{"KOREA":"잘 지내지 않을까? 무소식이 희소식이라는 말도 있잖아.","JPN":"元気じゃない？　便りのないのはいい便りって言うし。","ENG":"She is probably fine. No news is good news, right?","TWN":"應該過得不錯吧？不是有句話叫「沒消息就是好消息」嗎？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"뭐, 나도 그랬으면 좋겠는데 말이지.","JPN":"まあ、そうならいいんだけど。","ENG":"Yeah, I hope so too.","TWN":"我也希望是這樣啦。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"왠지 리온은 늘 위축되어 있어서, 왠지 모르게 걱정된다고 해야 할까……?","JPN":"リオンはいつもおどおどしてるから、心配っていうか……","ENG":"She always seemed so timid. I can't help worrying about her...","TWN":"我總覺得萊恩一直都很畏縮，莫名讓人有點擔心……"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"PUPPET_OZ_NULL_NULL","text":{"KOREA":"맥박 지수 상승. 도로시는 부끄럼쟁이네.","JPN":"脈拍数上昇。ドロシーは照れ屋だね。","ENG":"Pulse rising. Dorothy is shy.","TWN":"脈搏指數上升，桃樂絲還真害羞呢。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L22_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"시, 시끄럽거든!?","JPN":"な、何言ってんだよ。","ENG":"H-hey, knock it off!","TWN":"吵、吵死了啦！？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"PUPPET_OZ_NULL_NULL","text":{"KOREA":"그럼, 확인해 볼래?","JPN":"じゃあ確かめてみる？","ENG":"Want me to check, then?","TWN":"那要不要確認一下？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"……응?","JPN":"……うん？","ENG":"...Huh?","TWN":"……嗯？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"뭐어어어? 아니, 어떻게……?","JPN":"ええええ？　いや、どうやって……？","ENG":"What? How did you even...?","TWN":"什麼？不，怎麼會……？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L28_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"원래 연락처로는 도통 연락이 안 되던데? 설마 따로 연락처라도 받아 둔 거야?","JPN":"もとの連絡先じゃ全然繋がらなかったけど？　あ、私が知らない番号とか他にあったとか？","ENG":"I could never reach her through her regular contact info. Did you get a separate contact or something?","TWN":"原本的資訊完全聯絡不上，難道你有他另外的聯絡方式？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"PUPPET_OZ_NULL_NULL","text":{"KOREA":"아니, 그런 건 아니고.","JPN":"ううん、そうじゃなくて。","ENG":"No, nothing like that.","TWN":"不，不是那樣的。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"PUPPET_OZ_NULL_NULL","text":{"KOREA":"오즈 프로젝트의 마지막 심부름 기억나?","JPN":"プロジェクト・オズの最後のお使い、覚えてる？","ENG":"Do you remember the last errand from the OZ Project?","TWN":"你還記得奧茲計畫最後一次跑腿嗎？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"AUTO_OPR_NULL_NULL","text":{"KOREA":"열람 암호 확인. <color=#ffd34c>팀 오즈</color>의 마지막 심부름입니다.","JPN":"閲覧パスワードの確認。<color=#ffd34c>チーム・オズ</color>の最後のお使いです。","ENG":"Access code confirmed. This is the last errand for <color=#ffd34c>Team OZ</color>.","TWN":"確認開啟密碼。<color=#ffd34c>奧茲國</color>最後的任務。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_07","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"AUTO_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L35_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"마지막 심부름이라고?","JPN":"最後のお使いって？","ENG":"Did it just say the last errand?","TWN":"最後的任務？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_07","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"기다려. 더 들어보자.","JPN":"待って。もう少し聞いてみよう。","ENG":"Hold on. We should listen more.","TWN":"等一下，先聽完再說。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_07","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L38_1","type":"dialog","speaker":"AUTO_OPR_NULL_NULL","text":{"KOREA":"<color=#ffd34c>기생체</color>의 위치가 확인되었습니다.","JPN":"<color=#ffd34c>寄生体</color>の位置が確認されました。","ENG":"The location of <color=#ffd34c>the parasite</color> has been confirmed.","TWN":"發現<color=#ffd34c>寄生物</color>的位置。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_07","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"AUTO_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"AUTO_OPR_NULL_NULL","text":{"KOREA":"해당 목표물의 위치로 이동하여 원하는 대로 처리해도 좋다는 메시지입니다.","JPN":"該当ターゲットの位置に移動して、好きなように処理してもいいというメッセージです。","ENG":"You may head to the target's location and terminate as desired.","TWN":"移動至該目標物的位置後，可任憑你們處置。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_07","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"AUTO_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"PUPPET_OZ_NULL_NULL","text":{"KOREA":"그때 다운로드 받았던 기생체, <color=#ffd34c>토토</color>의 위치 신호가 아직 메모리에 저장되어 있거든.","JPN":"あの時ダウンロードした寄生体、<color=#ffd34c>トト</color>の位置信号がまだメモリーに残っているんだよね。","ENG":"The parasite <color=#ffd34c>Toto</color> we downloaded back then. Its location signal is still stored in memory.","TWN":"那時下載的寄生物<color=#ffd34c>托托</color>的位置訊號，現在還留在記憶體裡。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"PUPPET_OZ_NULL_NULL","text":{"KOREA":"그 신호를 전 세계 네트워크에 조회해 보면, 리온이 어디 있는지 알 수 있어.","JPN":"その信号を全世界のネットワークに照会すれば、リオンがどこにいるかわかるってこと。","ENG":"If I query that signal across the global network, I can find out where Liona is.","TWN":"只要把那個訊號丟進全球網路查詢，就能知道萊恩在哪裡。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"PUPPET_OZ_NULL_NULL","text":{"KOREA":"그라운드 원에 있는 아카데미에서 신호가 잡히면, 그럭저럭 잘 지내는 거 아닐까?","JPN":"グラウンド・ワンにあるアカデミーで信号が確認されたら、元気にやってるってことじゃない？","ENG":"If the signal shows up at the Academy in Ground One, she is probably doing fine.","TWN":"如果是在G1的學院捕捉到訊號，那應該就表示他過得還行吧？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"그, 그런 방법이……?","JPN":"そ、そんな方法が……？","ENG":"Th-that's possible...?","TWN":"居、居然還有這種方法……？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"잠깐, 그보다 왜 그걸 이제서야 말하는데? 내가 얼마나 걱정한 줄 알기나 해?","JPN":"って、なんでそれを今まで言わなかったんだよ？　私がどれだけ心配してたかわかる？","ENG":"Wait, more importantly, why are you only telling me this now? Do you know how worried I've been?","TWN":"等等，那你為什麼現在才說！？你知道我有多擔心嗎！"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"PUPPET_OZ_NULL_NULL","text":{"KOREA":"그야 네가 안 물어봤잖아?","JPN":"だって聞かれなかったから。","ENG":"Because you did not ask.","TWN":"你也沒問啊？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"PUPPET_OZ_NULL_NULL","text":{"KOREA":"그럼, 한다?","JPN":"じゃあ、やるよ？","ENG":"So, should I do it?","TWN":"那要試試看嗎？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"PUPPET_OZ_NULL_NULL","text":{"KOREA":"눈에서 빔~ 프로젝터~","JPN":"目からビ～ム、プロジェクタ～。","ENG":"Gazer beeeeeeam.","TWN":"從眼睛～投影～"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"PUPPET_OZ_NULL_NULL","text":{"KOREA":"어라? 이상하네?","JPN":"あれ？　おかしいな。","ENG":"Huh? Strange.","TWN":"咦？奇怪？"},"stage":{"bg":"MAINSTREAM_5201002","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"PUPPET_OZ_NULL_NULL","text":{"KOREA":"생체 신호가 이전이랑 달라졌나? 아니지. 그 둔탱이가 이런 걸 눈치챌 리 없는데?","JPN":"生体信号が変わったのかな？　いや、あのにぶちんが気づくわけないんだけど。","ENG":"Did the biometric signal change? No, that cannot be it. That simpleton would never notice something like this.","TWN":"生物訊號和之前不一樣？不對，那個木頭腦袋不可能察覺這種事啊？"},"stage":{"bg":"MAINSTREAM_5201002","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"왜? 무슨 문제라도 있는 거야?","JPN":"どうした？　何か問題でもあんの？","ENG":"Why? Is something wrong?","TWN":"怎麼了？有什麼問題嗎？"},"stage":{"bg":"MAINSTREAM_5201002","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"PUPPET_OZ_NULL_NULL","text":{"KOREA":"문제라기 보단, 토토의 위치 정보가 포착되고 있는 곳이 이상해.","JPN":"問題というか、トトの位置情報が変なところから現れている。","ENG":"It is not exactly a problem, but the place where Toto's location is being detected is strange.","TWN":"與其說是問題，不如說托托的位置資訊有點奇怪。"},"stage":{"bg":"MAINSTREAM_5201002","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"PUPPET_OZ_NULL_NULL","text":{"KOREA":"신호가 여기 샤레이드에서 잡히고 있어.","JPN":"ここ、シャレードにいるって。","ENG":"The signal is coming from Charade.","TWN":"訊號在查雷德捕捉到了。"},"stage":{"bg":"MAINSTREAM_5201002","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L21_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"샤레이드라고……?","JPN":"シャレード……？","ENG":"Charade...?","TWN":"查雷德……？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"PUPPET_OZ_NULL_NULL","text":{"KOREA":"그것도 여기서 아주 가까워.","JPN":"しかも今のワタシたちとかなり近い。","ENG":"And it is very close to us.","TWN":"而且就在這附近。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"subtitle","speaker":null,"text":{"KOREA":"관리국 직할 도시 <color=#ffd34c>샤레이드</color> 상업 지구\\n어느 뒷골목","JPN":"管理局直轄都市<color=#ffd34c>シャレード</color>商業地区\\nどこかの路地裏","ENG":"Administration Direct Control City, <color=#ffd34c>Charade</color> Commercial District\\nBack alley","TWN":"管理局直轄城市<color=#ffd34c>查雷德</color>商業區\\n某條後巷"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CULTIST_CAMPAMENTO_NULL_NULL","text":{"KOREA":"서둘러! 계시의 시간이 다가오고 있다!","JPN":"急げ！　啓示の時が近づいている！","ENG":"Hurry. The time of revelation is approaching.","TWN":"快點！啟示的時刻就要到了！"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L29_1","type":"dialog","speaker":"CULTIST_CAMPAMENTO_NULL_NULL","text":{"KOREA":"제물이 아직 멀리 도망가지는 못했을 거다! 반드시 숙주와 함께 파편을 확보해야 해!","JPN":"生贄はまだ遠くまでは逃げていないはずだ！　必ず宿主と共に破片を確保せねばならない！","ENG":"The sacrifice cannot have fled far yet. We must secure the fragment together with its host.","TWN":"祭品應該還沒逃遠！一定要連同宿主一起回收碎片！"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"하아, 하아, 하아……!","JPN":"はあ、はあ、はあ……！","ENG":"*Huff* *Huff* *Huff...!*","TWN":"哈啊、哈啊、哈啊……！"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"정말… 왜 이번에도 왜 일이 이렇게 된 거지……?","JPN":"もう……どうして今回もこうなったの……？","ENG":"Seriously... Why does it always turn out like this again...?","TWN":"真是的……怎麼這次事情又變成這樣啊……？"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"틀림없어… <color=#ffd34c>초대장</color>에 쓰여 있는 장소가 여기가 맞아.","JPN":"間違いない……<color=#ffd34c>招待状</color>の場所はここで合ってる。","ENG":"I'm sure of it... The place written on the <color=#ffd34c>invitation</color> is right here.","TWN":"不會錯的……<color=#ffd34c>邀請函</color>上寫的地點就是這裡。"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"마중 나온다는 <color=#ffd34c>기관원</color>이라는 사람은 대체 어디 있는 거지?","JPN":"迎えに来るっていう<color=#ffd34c>機関員</color>っていう人はどこにいるんだろう？","ENG":"Where is this so-called <color=#ffd34c>agent</color> who was supposed to meet me?","TWN":"說好會來迎接的<color=#ffd34c>機關成員</color>到底在哪？"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"어쩌면… 이건 함정이었을지도……","JPN":"まさか……これ、罠だったりしないよね……","ENG":"Maybe... this was a trap after all...","TWN":"難道……這其實是陷阱……"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"흐읏!?","JPN":"ふっ！？","ENG":"Hngh?!","TWN":"呃！？"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_CLATTER"},{"id":"L40_1","type":"dialog","speaker":"CULTIST_CAMPAMENTO_NULL_NULL","text":{"KOREA":"드디어 찾았군. 리오나 하트.","JPN":"やっと見つけた。リオナ・ハート。","ENG":"So we finally found you, Liona Hartt.","TWN":"終於找到你了，萊歐娜．哈特。"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L41_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"당신들은……?","JPN":"あなたたちは……？","ENG":"Who are you...?","TWN":"你們是……？"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"CULTIST_CAMPAMENTO_NULL_NULL","text":{"KOREA":"교구장이 전파한다! 파편과 그 숙주를 발견했다! 모든 신도는 이곳으로 집결하라!","JPN":"こちらは教区長！　破片とその宿主を見つけた！　全信徒は私のもとへ集結せよ！","ENG":"The diocesan head proclaims it. The Fragment and its host have been found. Followers, converge here.","TWN":"教區主教通告！已發現碎片與其宿主！所有信徒立刻集結此地！"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L44_1","type":"dialog","speaker":"CULTIST_CAMPAMENTO_NULL_NULL","text":{"KOREA":"우리는 계시의 인도에 따라, 신의 그릇을 확보한다!","JPN":"我々は啓示の導きに従い、神の器を確保する！","ENG":"By the guidance of revelation, we claim the god's vessel.","TWN":"我們將依循啟示的引導，回收神之器皿！"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"CULTIST_CAMPAMENTO_NULL_NULL","text":{"KOREA":"모든 것은 그분께서 점지한 계시에서 조금도 벗어나지 않을지니…….","JPN":"あの方の啓示から外れることは許されない……","ENG":"All of this follows the revelation bestowed by Him, without the slightest deviation...","TWN":"一切都不會偏離祂降下的啟示……"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CULTIST_VATICAN_SUPPLEMENT_NPC","face":"UNIT_IDLE"},"C":{"char_id":"CULTIST_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"CULTIST_CAMPAMENTO_NULL_NULL","text":{"KOREA":"저항을 포기하고 우리를 따라오거라, 신을 담는 그릇이여.","JPN":"抵抗を諦め、我々について来い。神の器よ。","ENG":"Abandon resistance and come with us, vessel that bears god.","TWN":"放棄抵抗跟我們走吧，承載神之人啊。"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CULTIST_VATICAN_SUPPLEMENT_NPC","face":"UNIT_IDLE"},"C":{"char_id":"CULTIST_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_SWORD_MOVEMENT"},{"id":"L50_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"아니… 당신들이 누구인지는 중요하지 않겠죠…….","JPN":"でも……相手が誰かなんて、もう今更のこと……","ENG":"I mean... I guess it doesn't really matter who you are...","TWN":"不管你們是誰，其實也不重要了……"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"어차피 위저드도, 가면 쓴 사람들도… 다들 토토를 노리고 있었으니까…….","JPN":"どうせウィザードも、仮面の人たちも……みんなトトを狙ってたから……","ENG":"Wizard and masked people... Everyone was after Toto anyway...","TWN":"反正不管是魔法師還是戴面具的人……全都是衝著托托來的……"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"토토가 무엇인지, 내가 왜 이런 일을 당해야 하는지 가르쳐 줄 생각도 없으면서……!","JPN":"トトが何なのか、どうして私がこんな目に遭わなきゃいけないのか、教えてくれるつもりもないくせに……！","ENG":"None of you ever explain what Toto is, or why I have to go through this...","TWN":"卻連托托是什麼、我為什麼非得遭遇這種事，都不打算告訴我……！"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"당신들 같은 사람들은 이제 지긋지긋해!","JPN":"あなたたちみたいな人はもううんざり！","ENG":"I'm sick of people like you!","TWN":"我已經受夠你們這種人了！"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L5_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"나도 동감이야, 토토.","JPN":"私も同じ気持ちだよ、トト。","ENG":"I feel the same, Toto.","TWN":"我也一樣，托托。"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"간신히 너에 대한 <color=#ffd34c>실마리</color>를 잡았는데, 물러설 생각은 없어.","JPN":"やっとあなたの<color=#ffd34c>手がかり</color>が見つかったのに、引き下がるつもりはない。","ENG":"I finally found a <color=#ffd34c>lead</color> about you, and I'm not backing down.","TWN":"好不容易才找到關於你的<color=#ffd34c>線索</color>，我不會退縮的。"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"이게 함정이라고 해도, 나는 싸울 거야.","JPN":"これが罠だとしても、私は戦う。","ENG":"Even if this is a trap, I will fight.","TWN":"就算這是陷阱，我也要戰鬥。"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"그러니까 힘을 빌려줘, 토토.","JPN":"だから力を貸して、トト。","ENG":"So lend me your power, Toto.","TWN":"所以借我力量吧，托托。"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CULTIST_CAMPAMENTO_NULL_NULL","text":{"KOREA":"어리석군. 본디 운명이라는 것이 거대한 파도와 같은 것.","JPN":"愚かな。運命とは本来巨大な波のようなもの。","ENG":"Foolish. Fate is like a massive wave by nature.","TWN":"真愚蠢。命運本就是如同巨浪的存在。"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"CULTIST_VATICAN_SUPPLEMENT_NPC","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"CULTIST_CAMPAMENTO_NULL_NULL","text":{"KOREA":"그것에 휩쓸린 자는 아무리 도망친다고 한들 결코 흐름에서 벗어날 수 없지.","JPN":"それに呑まれたら最後、いくら足掻こうとも流れを脱することはできない。","ENG":"Those caught in it can never escape its flow, no matter how they run.","TWN":"一旦被捲入其中，不管怎麼逃都不可能脫離洪流。"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"CULTIST_VATICAN_SUPPLEMENT_NPC","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"CULTIST_CAMPAMENTO_NULL_NULL","text":{"KOREA":"그러니 가여운 네 운명을 탓하며, 얌전히 제물이…….","JPN":"哀れな己の運命を嘆き、大人しく生贄に……","ENG":"So curse your pitiful fate and quietly become our sacrifice...","TWN":"所以要就怨恨你那可悲的命運，乖乖成為祭品……"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"CULTIST_VATICAN_SUPPLEMENT_NPC","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_QM","text":{"KOREA":"글쎄? 내 생각은 좀 다른데?","JPN":"へえ？　私はそう思わないけど。","ENG":"I don't know. I see it differently.","TWN":"是嗎？我倒不這麼認為耶？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"CULTIST_VATICAN_SUPPLEMENT_NPC","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_QM","text":{"KOREA":"파도가 닥쳐온다고 해도, 그것보다 더 빨리 달려서 도망치면 되잖아?","JPN":"波が押し寄せてきたら、それより速く走って逃げればいいじゃん？","ENG":"Even if a wave comes crashing in, you just have to run faster than it.","TWN":"就算巨浪襲來，只要跑得比它快，不就能逃掉了嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"CULTIST_VATICAN_SUPPLEMENT_NPC","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"CULTIST_CAMPAMENTO_NULL_NULL","text":{"KOREA":"으음?","JPN":"うむ？","ENG":"Huh?","TWN":"嗯？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"CULTIST_VATICAN_SUPPLEMENT_NPC","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"잠깐, 이 목소리는 설마……?","JPN":"あっ、この声って……！","ENG":"Wait, that voice... Is that...?","TWN":"等等，這個聲音該不會是……？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"리온, 오랜만이야. 잘 지냈어?","JPN":"リオン、久しぶり。元気にしてた？","ENG":"Long time no see, Liona. Been doing well?","TWN":"萊恩，好久不見。最近過得怎麼樣啊？"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_PRIDE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L25_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"아니, 보아하니 그다지 잘 지낸 것 같지는 않지만.","JPN":"いや、見た感じそれほど元気じゃなさそうだな。","ENG":"Well, judging by the looks of it, I guess not.","TWN":"不對，看起來好像不怎麼好。"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L26_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"그러고 보니, 아마 처음 만났을 때도 지금처럼 쫓기고 있었지?","JPN":"そういえば初めて出会った時も今みたいに追われてたよね。","ENG":"Come to think of it, you were being chased the first time we met too, just like now.","TWN":"這麼說來，我們第一次見面的時候，你也是像現在這樣被追著跑吧？"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L27_1","type":"dialog","speaker":"PUPPET_OZ_NULL_NULL","text":{"KOREA":"내 메모리에 따르면, 그때는 우리가 리온을 쫓긴 했지만.","JPN":"ワタシのメモリーによると、当時はワタシたちがリオンを追う立場だった。","ENG":"According to my memory, we were the ones chasing her back then.","TWN":"根據我的記憶，那時候是我們在追萊恩。"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L29_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"도로시, 허수아…? 너희들이 여기 어떻게……?","JPN":"ドロシーちゃん、コトリちゃん……？　どうしてここに……？","ENG":"Dorothy, Skia...? How are you two here...?","TWN":"桃樂絲、禾蘇亞……？你們怎麼會在這裡……？"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"뭐, 이런저런 사정이 있었어. 나중에 감자튀김이라도 먹으면서 이야기하자고.","JPN":"まあ、色々あってさ。後でフライドポテトでも食べながらゆっくり話そう。","ENG":"Well, a lot happened. Let's talk later over some fries or something.","TWN":"總之發生了不少事，之後邊吃薯條邊聊吧。"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"지금은 내 친구 건드린 녀석들을 혼내 주는 게 먼저니까.","JPN":"今は友達を困らせてるやつらを懲らしめてやるのが先だから。","ENG":"Right now, we need to deal with the people messing with my friend.","TWN":"現在得先教訓一下動我朋友的傢伙。"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"그럼, 오랜만에 기어를 올려볼까?","JPN":"じゃあ、久しぶりにギアを上げてみようか？","ENG":"Then. It's time I shifted into high gear for the first time in a while.","TWN":"那麼來點久違的加速吧？"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"}]`);export{e as default};